            // Función para mostrar/ocultar el botón
            function toggleScrollButton() {
                const btn = document.getElementById('scroll-top-btn');
                if (window.scrollY > 400) {
                    btn.style.display = 'flex';
                    btn.style.opacity = '1';
                } else {
                    btn.style.opacity = '0';
                    setTimeout(() => {
                        if (window.scrollY <= 400) {
                            btn.style.display = 'none';
                        }
                    }, 300);
                }
            }
            
            // Event listeners
